// 前序遍历（根-左-右）
function preorderTraversal(node) {
  if (!node) return [];
  const result = [];
  result.push(node.value);
  result.push(...preorderTraversal(node.left));
  result.push(...preorderTraversal(node.right));
  return result;
}

// 中序遍历（左-根-右）
function inorderTraversal(node) {
  if (!node) return [];
  const result = [];
  result.push(...inorderTraversal(node.left));
  result.push(node.value);
  result.push(...inorderTraversal(node.right));
  return result;
}

// 后序遍历（左-右-根）
function postorderTraversal(node) {
  if (!node) return [];
  const result = [];
  result.push(...postorderTraversal(node.left));
  result.push(...postorderTraversal(node.right));
  result.push(node.value);
  return result;
}

// 示例调用
const tree = {
  value: 10,
  left: {
    value: 5,
    left: { value: 3 },
    right: { value: 7 }
  },
  right: {
    value: 15,
    left: { value: 12 },
    right: { value: 20 }
  }
};

