function binarySearch(arr, target) {
  let left = 0;
  let right = arr.length - 1;
  
  while (left <= right) {
    const mid = Math.floor((left + right) / 2);
    
    if (arr[mid] === target) {
      return mid; // 找到目标
    } else if (arr[mid] > target) {
      right = mid - 1; // 目标在左半部分
    } else {
      left = mid + 1; // 目标在右半部分
    }
  }
  
  return -1; // 未找到目标
}

